-- 시드 데이터: 데모 팀/경기/유저
-- 주의: 실제 Supabase에서는 auth.users로 사용자를 먼저 생성해야 함
-- 이 시드는 로컬 개발/테스트 목적

-- 데모 사용자 (Supabase Auth 사용 시 auth.users에 먼저 생성 필요)
ON CONFLICT (id) DO NOTHING;

-- 데모 팀
ON CONFLICT (id) DO NOTHING;

-- 팀 멤버
ON CONFLICT (team_id, user_id) DO NOTHING;

-- 데모 경기 (OPEN 상태 - 투표 진행 중)
   '주말 리그전', '2026-02-15T14:00:00+09:00', '잠실 운동장', 'FC 태풍', 'OPEN',
   '00000000-0000-0000-0000-000000000001'),
  ('20000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000001',
   '연습 경기', '2026-02-22T10:00:00+09:00', '올림픽공원', NULL, 'OPEN',
   '00000000-0000-0000-0000-000000000002')
ON CONFLICT (id) DO NOTHING;

-- 데모 출석 투표 (첫 번째 경기)
ON CONFLICT (match_id, user_id) DO NOTHING;

-- 두 번째 경기 출석 투표
ON CONFLICT (match_id, user_id) DO NOTHING;

-- ============================================================
-- PoV 확장: 신규 10명 사용자 (006~015)
-- ============================================================
ON CONFLICT (id) DO NOTHING;

-- 신규 10명 FC 번개 팀 등록 (MEMBER)
ON CONFLICT (team_id, user_id) DO NOTHING;

-- 전체 15명 사용자 프로필 (포지션 배정)
ON CONFLICT (user_id) DO NOTHING;
